export function parseArgs(argv) {
  const result = { _: [] }
  let i = 0
  while (i < argv.length) {
    const arg = argv[i]
    if (!arg.startsWith('--')) {
      result._.push(arg)
      i++
      continue
    }
    if (arg.includes('=')) {
      const key = arg.slice(2)
      const value = arg.slice(arg.indexOf('=') + 1)
      result[key] = value
      i++
      continue
    }
    result[arg.slice(2)] = true
    i++
    if (i < argv.length) {
      const next = argv[i]
      if (!next.startsWith('--')) {
        result[arg.slice(2)] = next
        i++
      }
    }
  }
  return result
}

